const express = require('express');
const app = express();
const server = require('http').Server(app);
const io = require('socket.io')(server);

let players = {}; // Store all connected players here

// Middleware to validate player's username and score
function authenticatePlayer(req, res, next) {
  const {username, score} = req.body;
  
  if (!username || !score) {
    return res.status(400).send('Username and Score are required');
  }
  
  // You can add more validation rules here
  
  next();
}

io.use((socket, next) => {
  const handshakeData = socket.handshake;
  authenticatePlayer(handshakeData.query, {}, (error) => {
    if (!error) return next();
    
    console.log('Authentication error:', error);
    next(new Error(error));
  });
});

// Handle new player connection
io.on('connection', socket => {
  const {username, score} = socket.handshake.query;
  
  // Store the new player in memory
  players[socket.id] = {username, score};
  
  console.log(`Player ${username} connected with id: ${socket.id}`);
  
  io.emit('player-list', Object.values(players)); // Broadcast the updated player list to all clients
});

// Handle player disconnection
